def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-9
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 3:
            priority = (ratio ** 5) + (capacity % 4) * 3.5
            for k in range(1, int(capacity) + 4):
                if k % 3 == 0:
                    priority += np.tan(ratio / (k + epsilon)) * (k % 2 + 1)
                elif k % 2 == 0:
                    priority -= np.exp(-k / (ratio + epsilon))
                else:
                    priority += np.log(k + ratio + epsilon) / (k + 1)
            if capacity % 3 == 0:
                priority *= 1.15
            elif capacity % 5 == 0:
                priority /= 1.1
            else:
                priority += np.sqrt(priority + epsilon)
        elif 2 < ratio <= 3:
            priority = (ratio ** 3) * np.log(capacity + 2)
            for m in range(1, int(item) * 2):
                if m % 4 == 0:
                    priority -= (m / (capacity + 2)) ** 3
                elif m % 2 == 0:
                    priority += np.sin(m / (item + epsilon))
                else:
                    priority -= np.sqrt(m * ratio) / (m + 1)
            priority = max(priority, 0)
        elif 1 < ratio <= 2:
            priority = (ratio ** 2) * np.log(capacity + 1)
            for m in range(1, int(item) + 1):
                if m % 3 == 0:
                    priority += (m / (capacity + 1)) ** 2
                else:
                    priority -= m / (item + epsilon)
            priority = max(priority, 0)
        elif 0.5 < ratio <= 1:
            priority = -np.log(1 - ratio + epsilon) * np.cos(ratio * np.pi)
            factor = 1
            for n in range(1, 7):
                factor *= (ratio + n / (capacity + 2))
                if factor > 7:
                    break
            priority *= factor ** 1.2
            if capacity % 2 == 0:
                priority += np.sqrt(capacity / (item + epsilon))
        elif 0.2 < ratio <= 0.5:
            total = 0
            for j in range(1, int(capacity) + 1):
                val = (ratio ** (j ** 1.5)) / (j + epsilon)
                if j % 2 == 0:
                    val *= -1
                total += val
            priority = abs(total) + 0.7
            priority += np.tanh(item / (capacity + epsilon))
        else:
            total = 0
            for j in range(1, int(capacity) + 2):
                sign = -1 if (j ** 2) % 3 == 0 else 1
                val = sign * np.sin(ratio * j) / (j + epsilon)
                total += val
                if abs(total) > 3:
                    total /= 2
            priority = abs(total) + 0.6
            if priority < 0.1:
                priority += np.log(capacity + 1)
        if capacity < item:
            diff = (item - capacity)
            penalty = diff * 20
            for p in range(1, int(diff) * 2):
                if p % 5 == 0:
                    penalty += np.log(p + 2)
                elif p % 2 == 0:
                    penalty -= p * 0.15
                else:
                    penalty += np.sqrt(p)
            penalty = max(penalty, 0)
            priority += penalty
        else:
            bonus = np.sqrt(capacity - item + epsilon)
            for q in range(1, int(capacity - item + 1)):
                if q % 3 == 0:
                    bonus += np.log(q + 1)
                else:
                    bonus -= (q / (capacity + 1)) ** 0.5
            bonus = max(bonus, 0)
            priority -= bonus / 10
        priorities[i] = priority
    return priorities
